preToolUse.powershell:
$input = $Input | ConvertFrom-Json
$toolName = $input.toolName
$toolArgs = $input.toolArgs | ConvertFrom-Json -ErrorAction SilentlyContinue

if ($toolName -ne 'bash') { exit 0 }

$cmd = $toolArgs.command
if ($cmd -notmatch '^git\s+(commit|push)') { exit 0 }

Write-Host 'Running lint and tests before git operation...' -ForegroundColor Yellow

$lintResult = npm run lint 2>&1
if ($LASTEXITCODE -ne 0) {
  @{ decision = 'block'; reason = 'ESLint failed. Fix lint errors before committing.' } | ConvertTo-Json -Compress
  exit 0
}

$testResult = npx vitest run tests/unit 2>&1
if ($LASTEXITCODE -ne 0) {
  @{ decision = 'block'; reason = 'Unit tests failed. Fix tests before committing.' } | ConvertTo-Json -Compress
  exit 0
}

Write-Host 'Lint and tests passed.' -ForegroundColor Green
exit 0
